def run():
    existing_nums = set(Autorisation.objects.values_list('numero_auto', flat=True))
    created = skipped = errors = 0

    print(f"Démarrage import — {len(GPS_DATA)} coordonnées GPS")
    print(f"Autorisations existantes en BD : {Autorisation.objects.count()}")
    print()

    for rec in GPS_DATA:
        try:
            # Vérifier doublon par ID historique (pas par coordonnées)
            num_hist = f"HIST-{rec['type']}-{rec['id']}"
            if num_hist in existing_nums:
                skipped += 1
                continue

            existing_nums.add(num_hist)

            Autorisation.objects.create(
                numero_auto       = num_hist,
                type              = rec['type'],
                wilaya            = '',
                adresse           = rec['nom'][:255],
                latitude          = round(rec['lat'], 6),
                longitude         = round(rec['lon'], 6),
                date_delivrance   = date(2024, 1, 1),
                statut            = 'active',
                source_historique = True,
            )
            created += 1
            if created % 100 == 0:
                print(f"  {created}/{len(GPS_DATA)} créés...")

        except Exception as e:
            print(f"  Erreur ID {rec.get('id','?')}: {e}")
            errors += 1

    print()
    print("✅ Import terminé !")
    print(f"   Créés    : {created}")
    print(f"   Ignorés  : {skipped} (déjà importés)")
    print(f"   Erreurs  : {errors}")
    print(f"   Total BD : {Autorisation.objects.count()} autorisations")
    print()
    bp  = Autorisation.objects.filter(type='BP').count()
    usi = Autorisation.objects.filter(type='UNITE').count()
    print(f"   → Boulangeries BP  : {bp}")
    print(f"   → Usines UNITE     : {usi}")

if __name__ == '__main__':
    run()